file.content:
{
	"$schema": "https://schemas.wp.org/trunk/block.json",
	"apiVersion": 3,
	"name": "gatherpress/taxonomy-colors",
	"version": "0.1.2",
	"title": "Taxonomy Color Roadmap",
	"category": "widgets",
	"icon": "analytics",
	"description": "A comprehensive 6-layer architectural roadmap for implementing taxonomy color-coding in WordPress, so term colors behave like native theme palette entries — including scoped per-post resolution for Query Loop contexts and shadow taxonomy support for post types.",
	"example": {
		"attributes": {
			"showCodeExamples": true,
			"defaultExpanded": false
		}
	},
	"attributes": {
		"showCodeExamples": {
			"type": "boolean",
			"default": true
		},
		"defaultExpanded": {
			"type": "boolean",
			"default": false
		},
		"accentColor": {
			"type": "string",
			"default": "#0073aa"
		}
	},
	"supports": {
		"html": false,
		"align": [ "wide", "full" ],
		"spacing": {
			"margin": true,
			"padding": true
		},
		"color": {
			"background": true,
			"text": false
		},
		"typography": {
			"fontSize": true
		}
	},
	"textdomain": "gatherpress-taxonomy-colors",
	"editorScript": "file:./index.js",
	"editorStyle": "file:./index.css",
	"style": "file:./style-index.css",
	"viewScript": "file:./view.js",
	"render": "file:./render.php"
}

/**
 * Block Registration: Taxonomy Color Roadmap
 *
 * @since 0.1.0
 */

import { registerBlockType } from '@wordpress/blocks';

import './style.scss';

import Edit from './edit';
import metadata from './block.json';

registerBlockType( metadata.name, {
	edit: Edit,
	save: () => null,
} );

/**
 * Edit Component: Taxonomy Color Roadmap
 *
 * @since 0.1.0
 */

import { __ } from '@wordpress/i18n';
import { useBlockProps, InspectorControls } from '@wordpress/block-editor';
import {
	PanelBody,
	ToggleControl,
	ColorPicker,
} from '@wordpress/components';

import './editor.scss';

/**
 * The Edit function.
 *
 * @param {Object}   props                           Block props.
 * @param {Object}   props.attributes                Current attribute values.
 * @param {boolean}  props.attributes.showCodeExamples Whether to display code snippets.
 * @param {boolean}  props.attributes.defaultExpanded  Whether phases start expanded.
 * @param {string}   props.attributes.accentColor      Hex color for accent elements.
 * @param {Function} props.setAttributes              Setter to update block attributes.
 *
 * @return {Element} The editor element tree.
 */
export default function Edit( { attributes, setAttributes } ) {
	const { showCodeExamples, defaultExpanded, accentColor } = attributes;

	const blockProps = useBlockProps( {
		className: 'taxonomy-color-roadmap__editor',
	} );

	return (
		<>
			<InspectorControls>
				<PanelBody
					title={ __( 'Roadmap Display', 'gatherpress-taxonomy-colors' ) }
					initialOpen={ true }
				>
					<ToggleControl
						__nextHasNoMarginBottom
						label={ __( 'Show Code Examples', 'gatherpress-taxonomy-colors' ) }
						help={
							showCodeExamples
								? __( 'Code snippets are visible in the roadmap.', 'gatherpress-taxonomy-colors' )
								: __( 'Code snippets are hidden for a cleaner read.', 'gatherpress-taxonomy-colors' )
						}
						checked={ showCodeExamples }
						onChange={ ( value ) =>
							setAttributes( { showCodeExamples: value } )
						}
					/>
					<ToggleControl
						__nextHasNoMarginBottom
						label={ __( 'Expand All Phases', 'gatherpress-taxonomy-colors' ) }
						help={
							defaultExpanded
								? __( 'All phases start expanded on the frontend.', 'gatherpress-taxonomy-colors' )
								: __( 'Phases start collapsed; visitors click to expand.', 'gatherpress-taxonomy-colors' )
						}
						checked={ defaultExpanded }
						onChange={ ( value ) =>
							setAttributes( { defaultExpanded: value } )
						}
					/>
				</PanelBody>
				<PanelBody
					title={ __( 'Accent Color', 'gatherpress-taxonomy-colors' ) }
					initialOpen={ false }
				>
					<ColorPicker
						color={ accentColor }
						onChange={ ( value ) =>
							setAttributes( { accentColor: value } )
						}
						enableAlpha={ false }
					/>
				</PanelBody>
			</InspectorControls>

			<div { ...blockProps }>
				<div className="taxonomy-color-roadmap__editor-placeholder">
					<svg
						className="taxonomy-color-roadmap__editor-icon"
						xmlns="http://www.w3.org/2000/svg"
						viewBox="0 0 24 24"
						width="48"
						height="48"
						aria-hidden="true"
						focusable="false"
					>
						<path
							fill={ accentColor }
							d="M3.5 18.5h17v-1H3.5v1zm0-4h10v-1h-10v1zm0-4h17v-1H3.5v1zm0-4h10v-1h-10v1z"
						/>
					</svg>
					<div className="taxonomy-color-roadmap__editor-text">
						<strong className="taxonomy-color-roadmap__editor-title">
						{ __( 'Taxonomy Color Roadmap', 'gatherpress-taxonomy-colors' ) }
					</strong>
					<span className="taxonomy-color-roadmap__editor-description">
						{ __(
							'A 6-layer architectural guide for per-taxonomy color-coding in WordPress using design tokens via theme.json + dynamic CSS custom properties — including shadow taxonomy support for post types. Preview the page to see the full roadmap.',
							'gatherpress-taxonomy-colors'
						) }
					</span>
					</div>
				</div>
				<div className="taxonomy-color-roadmap__editor-meta">
					<span
						className="taxonomy-color-roadmap__editor-badge"
						style={ { backgroundColor: accentColor } }
					>
						{ __( '6 Layers', 'gatherpress-taxonomy-colors' ) }
					</span>
					<span className="taxonomy-color-roadmap__editor-badge taxonomy-color-roadmap__editor-badge--secondary">
						{ showCodeExamples
							? __( 'Code examples: ON', 'gatherpress-taxonomy-colors' )
							: __( 'Code examples: OFF', 'gatherpress-taxonomy-colors' ) }
					</span>
					<span className="taxonomy-color-roadmap__editor-badge taxonomy-color-roadmap__editor-badge--secondary">
						{ defaultExpanded
							? __( 'Expanded by default', 'gatherpress-taxonomy-colors' )
							: __( 'Collapsed by default', 'gatherpress-taxonomy-colors' ) }
					</span>
				</div>
			</div>
		</>
	);
}

/**
 * Taxonomy Color Roadmap — Shared Styles (Frontend + Editor)
 *
 * HOW: This file is imported by `src/index.js`, which causes wp-scripts
 * to emit it as `build/style-index.css`. WordPress enqueues it on both
 * the frontend and inside the editor because `block.json` declares:
 *   "style": "file:./style-index.css"
 *
 * WHY shared: Ensures visual consistency between the editor placeholder
 * and the frontend roadmap. Base typography, spacing tokens, and color
 * variables are defined here so both contexts inherit them.
 *
 * NAMING: BEM convention — `.taxonomy-color-roadmap` is the Block,
 * `__phase` / `__header` / `__content` etc. are Elements,
 * `--expanded` / `--secondary` etc. are Modifiers.
 *
 * @since 0.1.0
 */

/* ------------------------------------------------------------------ */
/* CSS Custom Properties — single source of truth for theming         */
/* ------------------------------------------------------------------ */

/**
 * Root-level custom properties scoped to the block wrapper.
 *
 * WHY custom properties: Allows the `accentColor` attribute (set via
 * the inspector ColorPicker) to cascade through all child elements
 * without additional inline styles on each one. The `--roadmap-accent`
 * property is set as an inline style on the wrapper in render.php.
 */
.wp-block-gatherpress-taxonomy-colors {
	/**
	 * Default accent — overridden by inline `--roadmap-accent` from render.php.
	 */
	--roadmap-accent: #0073aa;

	/**
	 * Derived palette values computed from the accent.
	 * WHY: Keeps the phase backgrounds, borders, and badges visually
	 * consistent without hardcoding multiple color values.
	 */
	--roadmap-accent-light: color-mix(in srgb, var(--roadmap-accent) 12%, transparent);
	--roadmap-accent-border: color-mix(in srgb, var(--roadmap-accent) 30%, transparent);
	--roadmap-text: #1e1e1e;
	--roadmap-text-secondary: #636363;
	--roadmap-bg: #ffffff;
	--roadmap-bg-alt: #f9f9f9;
	--roadmap-code-bg: #282c34;
	--roadmap-code-text: #abb2bf;
	--roadmap-radius: 8px;
	--roadmap-spacing: 1.5rem;

	font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen-Sans, Ubuntu, Cantarell, "Helvetica Neue", sans-serif;
	line-height: 1.7;
	color: var(--roadmap-text);
}

/* ------------------------------------------------------------------ */
/* Block: taxonomy-color-roadmap                                       */
/* ------------------------------------------------------------------ */

/**
 * .taxonomy-color-roadmap — the outermost roadmap container.
 *
 * HOW: Applied to the root <div> in render.php via get_block_wrapper_attributes().
 * Contains the header, introduction, phase list, and footer.
 */
.taxonomy-color-roadmap {

	/**
	 * __header — The roadmap title area at the top.
	 *
	 * WHY: Provides a clear visual anchor. Uses the accent color as a
	 * left border to tie into the phase accent scheme.
	 */
	&__header {
		border-left: 4px solid var(--roadmap-accent);
		padding: var(--roadmap-spacing);
		margin-bottom: var(--roadmap-spacing);
		background: var(--roadmap-accent-light);
		border-radius: 0 var(--roadmap-radius) var(--roadmap-radius) 0;
	}

	/**
	 * __title — The main H2 heading of the roadmap.
	 */
	&__title {
		margin: 0 0 0.5rem;
		font-size: 1.75rem;
		font-weight: 700;
		color: var(--roadmap-text);
		line-height: 1.3;
	}

	/**
	 * __subtitle — The supporting tagline below the title.
	 */
	&__subtitle {
		margin: 0;
		font-size: 1rem;
		color: var(--roadmap-text-secondary);
		font-weight: 400;
	}

	/* ---------------------------------------------------------------- */
	/* Element: __intro — Introductory paragraph(s)                     */
	/* ---------------------------------------------------------------- */

	/**
	 * __intro — Wraps introductory sections (Core Problem, Architecture).
	 *
	 * WHY separate section: Gives context before the layers begin,
	 * framing the problem being solved and the high-level strategy.
	 */
	&__intro {
		background: var(--roadmap-bg-alt);
		border: 1px solid var(--roadmap-accent-border);
		border-radius: var(--roadmap-radius);
		padding: var(--roadmap-spacing);
		margin-bottom: calc(var(--roadmap-spacing) * 2);

		p {
			margin: 0 0 1rem;
			font-size: 0.9375rem;

			&:last-child {
				margin-bottom: 0;
			}
		}

		/**
		 * Ordered lists inside intro sections (e.g. "The Core Problem" goals).
		 */
		ol {
			margin: 0 0 1rem;
			padding-left: 1.5rem;

			li {
				margin-bottom: 0.5rem;
				font-size: 0.9375rem;
			}
		}
	}

	/**
	 * __intro-label — The "The Question" label badge.
	 */
	&__intro-label {
		display: inline-block;
		background: var(--roadmap-accent);
		color: #ffffff;
		font-size: 0.75rem;
		font-weight: 600;
		text-transform: uppercase;
		letter-spacing: 0.05em;
		padding: 0.25rem 0.75rem;
		border-radius: 4px;
		margin-bottom: 1rem;
	}

	/* ---------------------------------------------------------------- */
	/* Element: __phases — The ordered list of roadmap phases           */
	/* ---------------------------------------------------------------- */

	/**
	 * __phases — Container for all phase items.
	 *
	 * HOW: A simple vertical stack with spacing between phases.
	 * WHY no ordered list: Phases have complex internal structure
	 * (headers, content, code blocks) that benefit from div semantics
	 * over <li> elements. Phase numbers are generated decoratively.
	 */
	&__phases {
		display: flex;
		flex-direction: column;
		gap: var(--roadmap-spacing);
	}

	/* ---------------------------------------------------------------- */
	/* Element: __phase — A single roadmap phase                        */
	/* ---------------------------------------------------------------- */

	/**
	 * __phase — Individual phase container.
	 *
	 * HOW: A bordered card with a clickable header that toggles the
	 * content area's visibility via the `--expanded` modifier.
	 *
	 * WHY collapsible: The roadmap is long. Collapsing keeps the page
	 * scannable — users expand only the phases they care about.
	 */
	&__phase {
		border: 1px solid #e0e0e0;
		border-radius: var(--roadmap-radius);
		overflow: hidden;
		transition: border-color 0.2s ease;

		/**
		 * Hover state — subtle accent border to indicate interactivity.
		 */
		&:hover {
			border-color: var(--roadmap-accent-border);
		}
	}

	/**
	 * __phase-header — The clickable header bar of each phase.
	 *
	 * HOW: A <button> element for accessibility (keyboard + screen reader).
	 * Contains the phase number badge, title, summary, and chevron.
	 *
	 * WHY <button>: Natively focusable and activatable with Enter/Space.
	 * Avoids the need for tabindex and keydown handlers on a <div>.
	 */
	&__phase-header {
		display: flex;
		align-items: flex-start;
		gap: 1rem;
		width: 100%;
		padding: var(--roadmap-spacing);
		background: var(--roadmap-bg);
		border: none;
		cursor: pointer;
		text-align: left;
		font-family: inherit;
		font-size: inherit;
		color: var(--roadmap-text);
		line-height: 1.5;
		transition: background-color 0.15s ease;

		&:hover {
			background: var(--roadmap-accent-light);
		}

		&:focus-visible {
			outline: 2px solid var(--roadmap-accent);
			outline-offset: -2px;
		}
	}

	/**
	 * __phase-number — The circled phase number (1–6).
	 *
	 * WHY: Visual wayfinding — lets readers quickly identify which phase
	 * they're looking at, even when multiple phases are expanded.
	 */
	&__phase-number {
		flex-shrink: 0;
		display: flex;
		align-items: center;
		justify-content: center;
		width: 2.5rem;
		height: 2.5rem;
		border-radius: 50%;
		background: var(--roadmap-accent);
		color: #ffffff;
		font-weight: 700;
		font-size: 1rem;
	}

	/**
	 * __phase-info — The title + summary text group.
	 */
	&__phase-info {
		flex: 1;
		min-width: 0;
	}

	/**
	 * __phase-title — The phase's heading text.
	 */
	&__phase-title {
		display: block;
		font-size: 1.125rem;
		font-weight: 600;
		margin-bottom: 0.25rem;
	}

	/**
	 * __phase-summary — A brief one-line summary shown in the collapsed state.
	 */
	&__phase-summary {
		display: block;
		font-size: 0.875rem;
		color: var(--roadmap-text-secondary);
	}

	/**
	 * __phase-chevron — The expand/collapse arrow indicator.
	 *
	 * HOW: An inline SVG rotated via CSS transform when the phase is expanded.
	 * WHY SVG: Avoids icon font dependencies; renders crisply at any size.
	 */
	&__phase-chevron {
		flex-shrink: 0;
		width: 1.5rem;
		height: 1.5rem;
		margin-top: 0.5rem;
		transition: transform 0.25s ease;
		color: var(--roadmap-text-secondary);

		/**
		 * Modifier: rotated state when parent phase has `--expanded`.
		 */
		.taxonomy-color-roadmap__phase--expanded & {
			transform: rotate(180deg);
		}
	}

	/**
	 * __phase-content — The expandable body of each phase.
	 *
	 * HOW: Uses `max-height` + `overflow: hidden` for a CSS-driven
	 * expand/collapse animation. JavaScript toggles `--expanded` on
	 * the parent `.taxonomy-color-roadmap__phase`.
	 *
	 * WHY max-height: Allows a smooth transition without JS measurement.
	 * The large max-height value (200rem) ensures even long content
	 * is fully visible when expanded.
	 */
	&__phase-content {
		max-height: 0;
		overflow: hidden;
		transition: max-height 0.35s ease, padding 0.35s ease;
		padding: 0 var(--roadmap-spacing);

		/**
		 * Expanded state — content becomes visible with padding.
		 */
		.taxonomy-color-roadmap__phase--expanded & {
			max-height: 200rem;
			padding: 0 var(--roadmap-spacing) var(--roadmap-spacing);
		}

		/**
		 * Paragraphs inside phase content.
		 */
		p {
			margin: 0 0 1rem;
			font-size: 0.9375rem;

			&:last-child {
				margin-bottom: 0;
			}
		}

		/**
		 * Unordered lists inside phase content.
		 */
		ul {
			margin: 0 0 1rem;
			padding-left: 1.5rem;

			li {
				margin-bottom: 0.5rem;
				font-size: 0.9375rem;
			}
		}

		/**
		 * __checklist — Styled checklist for implementation status.
		 *
		 * WHY: Visually distinguishes completed (✅) and pending (⬜)
		 * items so that the roadmap serves as a living progress tracker.
		 * List-style is removed because status emoji serve as markers.
		 */
		.taxonomy-color-roadmap__checklist {
			list-style: none;
			padding-left: 0.25rem;

			li {
				padding: 0.35rem 0;
				border-bottom: 1px solid color-mix(in srgb, var(--roadmap-accent) 10%, transparent);
				font-size: 0.9375rem;

				&:last-child {
					border-bottom: none;
				}
			}
		}
	}

	/* ---------------------------------------------------------------- */
	/* Element: __code — Code example blocks                            */
	/* ---------------------------------------------------------------- */

	/**
	 * __code — Wraps a code example within a phase.
	 *
	 * HOW: A dark-themed <pre><code> block with horizontal scroll.
	 * WHY dark background: High contrast for readability; matches the
	 * convention developers expect from code documentation.
	 */
	&__code {
		background: var(--roadmap-code-bg);
		color: var(--roadmap-code-text);
		border-radius: 6px;
		padding: 1rem 1.25rem;
		margin: 1rem 0;
		overflow-x: auto;
		font-family: "SF Mono", "Fira Code", "Fira Mono", "Roboto Mono", monospace;
		font-size: 0.8125rem;
		line-height: 1.6;
		tab-size: 4;
		-webkit-overflow-scrolling: touch;

		code {
			background: none;
			padding: 0;
			font-size: inherit;
			color: inherit;
		}
	}

	/**
	 * __code-label — Language / context label above a code block.
	 *
	 * Example: "PHP — functions.php" or "Filter: wp_theme_json_data_theme"
	 */
	&__code-label {
		display: inline-block;
		font-size: 0.6875rem;
		font-weight: 600;
		text-transform: uppercase;
		letter-spacing: 0.06em;
		color: var(--roadmap-accent);
		margin-bottom: 0.5rem;
	}

	/* ---------------------------------------------------------------- */
	/* Element: __note — Callout boxes for important notes              */
	/* ---------------------------------------------------------------- */

	/**
	 * __note — A highlighted callout for key architectural decisions,
	 * warnings, or "why this matters" explanations.
	 *
	 * WHY: Breaks the monotony of prose and draws attention to the
	 * most critical pieces of advice in each phase.
	 */
	&__note {
		background: var(--roadmap-accent-light);
		border-left: 3px solid var(--roadmap-accent);
		border-radius: 0 6px 6px 0;
		padding: 1rem 1.25rem;
		margin: 1rem 0;
		font-size: 0.875rem;
		color: var(--roadmap-text);

		strong {
			color: var(--roadmap-accent);
		}
	}

	/* ---------------------------------------------------------------- */
	/* Element: __footer — Bottom summary / links                       */
	/* ---------------------------------------------------------------- */

	/**
	 * __footer — The closing section with a summary and further reading.
	 */
	&__footer {
		border-top: 2px solid var(--roadmap-accent-border);
		margin-top: calc(var(--roadmap-spacing) * 2);
		padding-top: var(--roadmap-spacing);
		text-align: center;
		color: var(--roadmap-text-secondary);
		font-size: 0.875rem;

		p {
			margin: 0 0 0.5rem;

			&:last-child {
				margin-bottom: 0;
			}
		}
	}

	/**
	 * __footer-tagline — Emphasised closing line.
	 */
	&__footer-tagline {
		font-weight: 600;
		color: var(--roadmap-accent);
	}
}

/**
 * Taxonomy Color Roadmap — Editor-Only Styles
 *
 * HOW: Imported by `src/edit.js`, which causes wp-scripts to emit
 * `build/index.css`. WordPress enqueues it only in the editor because
 * `block.json` declares `"editorStyle": "file:./index.css"`.
 *
 * WHY separate: The editor placeholder has a completely different DOM
 * structure from the frontend roadmap. Keeping these styles isolated
 * prevents unused CSS from shipping to the frontend.
 *
 * @since 0.1.0
 */

/**
 * .taxonomy-color-roadmap__editor — Root of the editor placeholder.
 *
 * HOW: Applied via the `className` prop in useBlockProps() in edit.js.
 * Contains the placeholder card and the meta badge row.
 */
.taxonomy-color-roadmap__editor {
	/**
	 * __editor-placeholder — The main card area containing the icon and text.
	 *
	 * WHY: Mimics the native WordPress block placeholder style (e.g.,
	 * the "Latest Posts" or "Archives" block placeholder in the editor).
	 * A dashed border signals "this is a placeholder, not final content."
	 */
	&-placeholder {
		display: flex;
		align-items: center;
		gap: 1rem;
		padding: 1.5rem;
		border: 2px dashed #ddd;
		border-radius: 8px;
		background: #fafafa;
	}

	/**
	 * __editor-icon — The decorative SVG icon.
	 *
	 * WHY: Provides quick visual identification of the block type
	 * when scanning a page with many blocks.
	 */
	&-icon {
		flex-shrink: 0;
		width: 48px;
		height: 48px;
		opacity: 0.8;
	}

	/**
	 * __editor-text — Container for the title and description.
	 */
	&-text {
		display: flex;
		flex-direction: column;
		gap: 0.25rem;
	}

	/**
	 * __editor-title — The bold block name.
	 */
	&-title {
		font-size: 1rem;
		font-weight: 600;
		color: #1e1e1e;
	}

	/**
	 * __editor-description — The brief helper text.
	 */
	&-description {
		font-size: 0.8125rem;
		color: #757575;
		line-height: 1.5;
	}

	/**
	 * __editor-meta — Row of status badges below the placeholder.
	 *
	 * WHY: Gives the editor at-a-glance confirmation of the current
	 * configuration (phase count, code visibility, expand state)
	 * without needing to open the inspector sidebar.
	 */
	&-meta {
		display: flex;
		flex-wrap: wrap;
		gap: 0.5rem;
		margin-top: 0.75rem;
	}

	/**
	 * __editor-badge — Individual status badge.
	 *
	 * Default style: accent-colored (used for the "6 Phases" badge).
	 */
	&-badge {
		display: inline-flex;
		align-items: center;
		padding: 0.25rem 0.625rem;
		font-size: 0.6875rem;
		font-weight: 600;
		color: #ffffff;
		border-radius: 4px;
		line-height: 1.4;

		/**
		 * Modifier: --secondary — Muted grey badge for boolean state indicators.
		 *
		 * WHY: Visually differentiates informational badges (grey) from
		 * the primary phase-count badge (accent-colored).
		 */
		&--secondary {
			background: #e0e0e0 !important;
			color: #555;
		}
	}
}

/**
 * View Script: Taxonomy Color Roadmap — Frontend Interactivity
 *
 * @since 0.1.0
 */

/**
 * Initializes expand/collapse behavior for all roadmap block instances.
 *
 * @return {void}
 */
function initRoadmapBlocks() {
	const blocks = document.querySelectorAll(
		'.wp-block-gatherpress-taxonomy-colors'
	);

	blocks.forEach( function initBlock( block ) {
		const headers = block.querySelectorAll(
			'.taxonomy-color-roadmap__phase-header'
		);

		headers.forEach( function bindToggle( header ) {
			header.addEventListener( 'click', function handlePhaseToggle() {
				const phase = header.closest(
					'.taxonomy-color-roadmap__phase'
				);

				if ( ! phase ) {
					return;
				}

				const isNowExpanded = phase.classList.toggle(
					'taxonomy-color-roadmap__phase--expanded'
				);

				header.setAttribute(
					'aria-expanded',
					isNowExpanded ? 'true' : 'false'
				);
			} );
		} );
	} );
}

if ( document.readyState === 'loading' ) {
	document.addEventListener( 'DOMContentLoaded', initRoadmapBlocks );
} else {
	initRoadmapBlocks();
}

